#include <bits/stdc++.h>
using namespace std;
const int N=102,M=1e4+4;
int t,n,m,f[N][M],p[N][N];
int main(){
    scanf("%d%d%d",&t,&n,&m);
    for(int i=1;i<=t;i++)
        for(int j=1;j<=n;j++)
            scanf("%d",&p[i][j]);
    for(int i=1;i<t;i++){
        for(int j=1;j<=n;j++)
            for(int k=p[i][j];k<=m;k++)
                f[i][k]=max(f[i][k],f[i][k-p[i][j]]+p[i+1][j]-p[i][j]);
        m+=f[i][m];
    }
    printf("%d",m);
    return 0;
}
